import Window from '../../src/window/Window.js';
import { ReadableStream } from 'stream/web';

describe('Repro abort', () => {
	it('rejects text() with AbortError on close()', async () => {
		const window = new Window();
		const response = new window.Response(
			new ReadableStream({
				start() {
					// never enqueue, never close -> read() hangs
				}
			})
		);

		const promise = response.text();
		// Give the read a tick to start
		await new Promise((r) => setTimeout(r, 5));
		window.happyDOM.close();

		let error: Error | null = null;
		try {
			await promise;
		} catch (e) {
			error = e as Error;
		}
		expect(error).toBeInstanceOf(window.DOMException);
		expect(error?.name).toBe('AbortError');
	});
});
